#include <bits/stdc++.h>
using namespace std;
typedef long long ll;

struct tree {
    int l, r;
    ll sum;
    ll add, mul;
} t[400005];

int n, mod, m;
ll a[100005];

void push_up(int p) {
    t[p].sum = (t[p * 2].sum + t[p * 2 + 1].sum) % mod;
}

void push_down(int p) {
    t[p * 2].mul = t[p * 2].mul * t[p].mul % mod;
    t[p * 2 + 1].mul = t[p * 2 + 1].mul * t[p].mul % mod;
    t[p * 2].add = (t[p * 2].add * t[p].mul + t[p].add) % mod;
    t[p * 2 + 1].add = (t[p * 2 + 1].add * t[p].mul + t[p].add) % mod;
    t[p * 2].sum = (
        t[p * 2].sum * t[p].mul + 
        t[p].add * (t[p * 2].r - t[p * 2].l + 1)
    ) % mod;
    t[p * 2 + 1].sum = (
        t[p * 2 + 1].sum * t[p].mul + 
        t[p].add * (t[p * 2 + 1].r - t[p * 2 + 1].l + 1)
    ) % mod;
    t[p].add = 0, t[p].mul = 1;
}

void build(int l, int r, int p) {
    t[p].l = l, t[p].r = r;
    t[p].add = 0, t[p].mul = 1;
    if (l == r) {
        t[p].sum = a[l];
        return ;
    }
    int mid = l + (r - l) / 2;
    build(l, mid, p * 2);
    build(mid + 1, r, p * 2 + 1);
    push_up(p);
}

void add(int l, int r, ll x, int p) {
    if (l <= t[p].l && t[p].r <= r) {
        t[p].sum = (t[p].sum + (t[p].r - t[p].l + 1) * x) % mod;
        t[p].add = (t[p].add + x) % mod;
        return ;
    }
    if (t[p].r < l || t[p].l > r) {
        return ;
    }
    push_down(p);
    add(l, r, x, p * 2);
    add(l, r, x, p * 2 + 1);
    push_up(p);
}

void mul(int l, int r, ll x, int p) {
    if (l <= t[p].l && t[p].r <= r) {
        t[p].sum = t[p].sum * x % mod;
        t[p].add = t[p].add * x % mod;
        t[p].mul = t[p].mul * x % mod;
        return ;
    }
    if (t[p].r < l || t[p].l > r) {
        return ;
    }
    push_down(p);
    mul(l, r, x, p * 2);
    mul(l, r, x, p * 2 + 1);
    push_up(p);
}

ll query(int l, int r, int p) {
    if (l <= t[p].l && t[p].r <= r) {
        return t[p].sum;
    }
    if (t[p].r < l || t[p].l > r) {
        return 0;
    }
    push_down(p);
    return (query(l, r, 2 * p) + query(l, r, 2 * p + 1)) % mod;
}

int main() {
    cin >> n >> mod;
    for (int i = 1; i <= n; i++) {
        cin >> a[i];
    }
    cin >> m;
    build(1, n, 1);
    while (m--) {
        int op;
        int t, g, c;
        cin >> op;
        switch (op) {
            case 1:
                cin >> t >> g >> c;
                mul(t, g, c, 1);
                break;
            case 2:
                cin >> t >> g >> c;
                add(t, g, c, 1);
                break;
            case 3:
                cin >> t >> g;
                cout << query(t, g, 1) << endl;
                break;
        }
    }
    return 0;
}
